package com.enterprise.app.controller;

import com.enterprise.app.entity.Transaction;
import com.enterprise.app.service.TransactionService;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;

@RestController
@RequestMapping("/api/transactions")
@RequiredArgsConstructor
public class TransactionController {
    
    private final TransactionService transactionService;
    
    @PostMapping("/user/{userId}")
    public ResponseEntity<Transaction> createTransaction(
            @PathVariable Long userId,
            @RequestBody Transaction transaction) {
        Transaction createdTransaction = transactionService.createTransaction(userId, transaction);
        return new ResponseEntity<>(createdTransaction, HttpStatus.CREATED);
    }
    
    @GetMapping("/{id}")
    public ResponseEntity<Transaction> getTransactionById(@PathVariable Long id) {
        Transaction transaction = transactionService.getTransactionById(id);
        return ResponseEntity.ok(transaction);
    }
    
    @GetMapping("/user/{userId}")
    public ResponseEntity<List<Transaction>> getUserTransactions(@PathVariable Long userId) {
        return ResponseEntity.ok(transactionService.getUserTransactions(userId));
    }
    
    @GetMapping("/user/{userId}/paginated")
    public ResponseEntity<Page<Transaction>> getUserTransactionsPaginated(
            @PathVariable Long userId,
            Pageable pageable) {
        return ResponseEntity.ok(transactionService.getUserTransactionsPaginated(userId, pageable));
    }
    
    @GetMapping("/user/{userId}/date-range")
    public ResponseEntity<List<Transaction>> getUserTransactionsByDateRange(
            @PathVariable Long userId,
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime startDate,
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime endDate) {
        return ResponseEntity.ok(transactionService.getUserTransactionsByDateRange(userId, startDate, endDate));
    }
    
    @GetMapping("/pending")
    public ResponseEntity<List<Transaction>> getPendingTransactions() {
        return ResponseEntity.ok(transactionService.getPendingTransactions());
    }
    
    @PostMapping("/{id}/process")
    public ResponseEntity<Transaction> processTransaction(@PathVariable Long id) {
        Transaction processedTransaction = transactionService.processTransaction(id);
        return ResponseEntity.ok(processedTransaction);
    }
    
    @PostMapping("/{id}/cancel")
    public ResponseEntity<Transaction> cancelTransaction(@PathVariable Long id) {
        Transaction cancelledTransaction = transactionService.cancelTransaction(id);
        return ResponseEntity.ok(cancelledTransaction);
    }
    
    @GetMapping("/user/{userId}/total")
    public ResponseEntity<BigDecimal> getUserTotalTransactions(
            @PathVariable Long userId,
            @RequestParam Transaction.TransactionStatus status) {
        BigDecimal total = transactionService.calculateUserTotalTransactions(userId, status);
        return ResponseEntity.ok(total);
    }
}

